import React, { useEffect, useState } from 'react';

function InicioForm({ onContinue }) {
  const [entrevistadores, setEntrevistadores] = useState([]);
  const [entrevistadorId, setEntrevistadorId] = useState('');
  const [postulante, setPostulante] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    fetch('http://localhost/sistema-entrevistas/backend/api/listar_entrevistadores.php')
      .then(res => res.json())
      .then(data => setEntrevistadores(data))
      .catch(err => {
        console.error("Error al cargar entrevistadores:", err);
        setError("No se pudieron cargar los entrevistadores.");
      });
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!entrevistadorId || !postulante.trim()) {
      setError('Debes seleccionar un entrevistador y escribir el nombre del postulante.');
      return;
    }

    try {
      const response = await fetch('http://localhost/sistema-entrevistas/backend/api/crear_postulante.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nombre: postulante })
      });

      const data = await response.json();
      if (data.status === 'ok') {
        onContinue(entrevistadorId, data.id);
      } else {
        setError('Error al registrar el postulante.');
      }
    } catch (err) {
      console.error(err);
      setError('No se pudo conectar al backend.');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h2>Inicio de entrevista</h2>

      <label>Selecciona al entrevistador:</label>
      <select
        value={entrevistadorId}
        onChange={(e) => setEntrevistadorId(e.target.value)}
        required
        style={{ display: 'block', width: '100%', padding: '8px', marginBottom: '10px' }}
      >
        <option value="">-- Selecciona --</option>
        {entrevistadores.map((e) => (
          <option key={e.id} value={e.id}>{e.nombre}</option>
        ))}
      </select>

    <label>Nombre del postulante:</label>
      <input
        type="text"
        value={postulante}
        onChange={(e) => setPostulante(e.target.value)}
        style={{ display: 'block', marginBottom: '10px', padding: '8px' }}
      />

      

      {error && <p style={{ color: 'red' }}>{error}</p>}

      <button type="submit" style={{ padding: '10px 20px' }}>
        Comenzar entrevista
      </button>
    </form>
  );
}

export default InicioForm;
